import{_ as a,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"2.十字军技能树","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/黑暗地牢能力组/2.十字军技能树.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/黑暗地牢能力组/2.十字军技能树.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/黑暗地牢能力组/2.十字军技能树.md"};function o(_,e,d,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"_2-十字军技能树",tabindex:"-1"},[p("2.十字军技能树 "),r("a",{class:"header-anchor",href:"#_2-十字军技能树","aria-label":'Permalink to "2.十字军技能树"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风020")])])],-1),n('<h1 id="十字军技能树" tabindex="-1">十字军技能树 <a class="header-anchor" href="#十字军技能树" aria-label="Permalink to &quot;十字军技能树&quot;">​</a></h1><p>十字军技能树</p><p>惩戒<br> 先决条件：购买暗黑地牢技艺组并选择十字军分支<br> 价格：D+750<br> 描述：圣光为刃，无坚不摧！<br> 效果：消耗1点意志力，结合于一次白刃攻击使用，你将自身的意志沉入刀刃，令其对那邪秽之物的杀伤力激增，猛增，劲增！<br> 你发动一次白刃攻击，你在本次攻击中额外获得5点破魔，若计算防御后仍有剩余破魔，则该能力提供的剩余破魔转换为攻击上的表现加值。<br> 在计算最终造成伤害时，你可以将其中3点严重伤害转化为韧性伤害。</p><p>热诚控诉<br> 先决条件：购买暗黑地牢技艺组并选择十字军分支<br> 价格：D+500<br> 描述：高呼信仰之名，泼洒神圣辉光。<br> 效果：消耗1点意志力，你以一个标准动作令神圣的光辉在此地爆射而出。立刻对前方扇形15m内的敌人进行一次神术攻击（【决心+学识（神学）+辅助专业：虔诚（专注）】），造成光能伤害，反射豁免。</p><p>眩晕击<br> 先决条件：购买暗黑地牢技艺组并选择十字军分支<br> 价格：D+500<br> 描述：伤而不杀，是为慈悲！<br> 效果：消耗1点意志力，消费一个标准动作进行一次普通近战攻击。你本次攻击将不会造成伤害，而是转化为眩晕点数。在本次攻击鉴定中，你额外获得2点附加成功。</p><p>信仰壁障<br> 先决条件：购买暗黑地牢技艺组并选择十字军分支<br> 价格：C+1250<br> 描述：此为圣光挥洒之地！<br> 效果：消耗1点意志力，以迅捷动作施展，令神圣的光辉在此地重现。你的周围将会有辉光洒落，立刻使周围15米范围内的亮度提升2级。在辉光照耀范围内的敌人受到攻击时，需要额外进行一次意志豁免，若豁免失败，则他们需要以你为首要攻击目标，这是一个C级的心灵胁迫效果，辉光持续一场景。<br> 购买该能力不会获得自由属性。</p><p>战斗治疗<br> 先决条件：购买暗黑地牢技艺组并选择十字军分支<br> 价格：D+500<br> 描述：粗糙的包扎治疗，仅能将人从鬼门关前拉回些许，随后让他们继续投身地狱般的战场。<br> 效果：消耗1意志力，以迅捷动作对一个接触距离内的友方单位使用，立刻将其身上2点伤害恢复至完好（医疗点24）。</p><p>圣矛<br> 先决条件：购买暗黑地牢技艺组并选择十字军分支，你需要以一把能够造成穿刺伤害武器施展该技艺。<br> 价格：D+500<br> 描述：圣光为矛，势如破竹！<br> 效果：消耗1意志力与一个整轮动作，你进行一次普通冲锋近战攻击，你在本次冲锋攻击中额外获得5点破甲和5点破魔。每轮一次，如若你成功以此方法对敌人造成伤害，则你可以立刻以自由动作再发动一次冲撞，本次冲撞成功数使用攻击成功数，并在此次对抗中获得3点技艺加值。从表现上看，这体现为你以武器将敌人挑起，随后用力将其甩飞。</p><p>激厉呐喊<br> 先决条件：购买暗黑地牢技艺组并选择十字军分支<br> 价格：D+750<br> 描述：拿起你们的武器，将喉中的锈味咽回！<br> 效果：以迅捷动作发动，你发出一声激励性的呐喊，使3.75米内的友方单位，自选消除其身上的一点任意异常点数（共用医疗点24）。<br> 购买这一能力不会获得自由属性。</p><p>热诚守护<br> 价格：D+500<br> 描述：当光芒短暂逝去，应当倍加小心。<br> 效果：当你与队友处于休息场景时，你可以花费30min的时间调动自身的感知，若如此做，则你在接下来的场景中无需休息也不会承受不休息带来的负面效果，获得依托于听觉的C级特异本质侦测能力。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
